import time
import json
import psutil
import ollama
import os # [BOOST] STRESS TEST 1M CONTEXT v1.0
# Valida o de limites reais de hardware (RAM/VRAM). def gerar_contexto_massivo(tamanho_tokens): """Gera um contexto fict cio de aproximadamente X tokens.""" base = "Isto um teste de estabilidade de contexto longo. " # Assumindo ~5 tokens por frase base repeticoes = tamanho_tokens // 8 return base * repeticoes def medir_sistema(): """Captura telemetria b sica do sistema.""" return { "ram_percent": psutil.virtual_memory().percent, "ram_gb": round(psutil.virtual_memory().used / (1024**3), 2) } def executar_stress(tokens=1000000, modelo="qwen2.5:1.5b"): print(f"[[HOT]] INICIANDO STRESS TEST: {tokens} tokens no modelo {modelo}...") # 1. Prepara o stats_inicial = medir_sistema() print(f"[[STATS]] Status Inicial: {stats_inicial}") start_gen = time.time() contexto = gerar_contexto_massivo(tokens) end_gen = time.time() print(f"[[OK]] Contexto gerado em {round(end_gen - start_gen, 2)}s. Tamanho: {len(contexto)} caracteres.") # 2. Infer ncia prompt = f"Baseado no texto acima, qual o objetivo deste teste? Responda em uma frase." options = { "num_ctx": tokens + 1000 # Margem de seguran a } print("[[OPS]] Enviando para o Ollama (Pre-fill massivo)... Aguarde...") try: start_inf = time.time() # Nota: O pre-fill de 1M tokens pode levar v rios minutos dependendo da GPU/RAM resposta = ollama.generate(model=modelo, prompt=contexto + "\n\n" + prompt, options=options) end_inf = time.time() duracao = end_inf - start_inf stats_final = medir_sistema() resultado = { "status": "sucesso", "tokens_alvo": tokens, "tempo_geracao_contexto": round(end_gen - start_gen, 2), "tempo_inferencia_s": round(duracao, 2), "ram_final_gb": stats_final["ram_gb"], "resposta": resposta.get('response', "") } except Exception as e: resultado = { "status": "erro", "mensagem": str(e), "ram_momento_erro": medir_sistema()["ram_gb"] } # 3. Salvando resultados benchmark_file = os.path.join(".panda", "benchmarks", f"stress_{time.strftime('%Y%m%d_%H%M%S')}.json") if not os.path.exists(".panda/benchmarks"): os.makedirs(".panda/benchmarks") with open(benchmark_file, "w", encoding="utf-8") as f: json.dump(resultado, f, indent=4) print(f"\n[ ] TESTE CONCLU DO. Resultado salvo em: {benchmark_file}") print(f"Status: {resultado['status']}") if resultado['status'] == "sucesso": print(f"Tempo de Inger ncia: {resultado['tempo_inferencia_s']}s") print(f"Resposta IA: {resultado['resposta']}") if __name__ == "__main__": # Inicia com 256k para seguran a, Lucas pode subir para 1M no comando manual executar_stress(tokens=256000)
